		bestCost := -1.0
		bestIdx := -1

		// Try inserting into every currently used assign.
		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			if !assign.AddShip(total_ship+j, oris[j], dess[j]) {
				continue
			}
			assign.GenRoute()
			if assign.Cost < 0 {
				assign.RemoveShip(total_ship + j)
				assign.GenRoute()
				continue
			}
			cost := assign.Cost
			assign.RemoveShip(total_ship + j)
